-- ============================================================
-- SuGanta Assistant v2 — persuasive, join-focused chatbot.
-- Replaces flow nodes in DB (idempotent). Uses JSON unicode
-- escapes for emojis (reliable across all encodings).
-- ============================================================

UPDATE flows SET
  name = 'SuGanta Assistant',
  description = 'Advanced education chatbot — hooks visitors, showcases value, and drives sign-ups for students, teachers, and institutes.',
  trigger_type = 'keyword',
  trigger_config = '{"keywords":["hi","hello","hey","menu","start","bot","suganta","help","join","register","signup","free"],"match_type":"contains"}'::jsonb,
  entry_node_id = 'start',
  fallback_policy = '{"on_unknown_reply":"reprompt","max_reprompts":2,"on_timeout_hours":24,"on_exhaust":"handoff"}'::jsonb,
  status = 'active',
  updated_at = NOW()
WHERE id = '9799fb41-aed1-4bb6-94e1-854d909a3666';

DELETE FROM flow_nodes WHERE flow_id = '9799fb41-aed1-4bb6-94e1-854d909a3666';


UPDATE flow_runs SET
  status = 'failed',
  end_reason = 'flow_upgraded_v2',
  ended_at = NOW()
WHERE flow_id = '9799fb41-aed1-4bb6-94e1-854d909a3666' AND status = 'active';
